#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define MAX_NODES 256
#define MAX_QUEUE 100

// Node structure for network simulation
typedef struct {
 int node_id;
 int num_neighbors;
 int neighbors[4]; // Maximum degree of 4 for mesh
 int packet_queue[MAX_QUEUE];
 int queue_front;
 int queue_rear;
} NetworkNode;

// Packet structure
typedef struct {
 int source;
 int destination;
 int current_node;
 int hops;
 int *path;
 int path_length;
} Packet;

// Network structure
typedef struct {
 int num_nodes;
 int topology_type;
 int rows;
 int cols;
 NetworkNode nodes[MAX_NODES];
} Network;

// Initialize mesh network
void init_mesh_network(Network *net, int rows, int cols) {
 net->num_nodes = rows * cols;
 net->topology_type = 1; // Mesh
 net->rows = rows;
 net->cols = cols;

 for (int i = 0; i < net->num_nodes; i++) {
 net->nodes[i].node_id = i;
 net->nodes[i].num_neighbors = 0;
 net->nodes[i].queue_front = 0;
 net->nodes[i].queue_rear = 0;

 int row = i / cols;
 int col = i % cols;

 // Add north neighbor
 if (row > 0) {
 net->nodes[i].neighbors[net->nodes[i].num_neighbors++] = 
 (row - 1) * cols + col;
 }
 // Add south neighbor
 if (row < rows - 1) {
 net->nodes[i].neighbors[net->nodes[i].num_neighbors++] = 
 (row + 1) * cols + col;
 }
 // Add west neighbor
 if (col > 0) {
 net->nodes[i].neighbors[net->nodes[i].num_neighbors++] = 
 row * cols + (col - 1);
 }
 // Add east neighbor
 if (col < cols - 1) {
 net->nodes[i].neighbors[net->nodes[i].num_neighbors++] = 
 row * cols + (col + 1);
 }
 }
}

// Initialize hypercube network
void init_hypercube_network(Network *net, int dimensions) {
 net->num_nodes = 1 << dimensions; // 2^dimensions
 net->topology_type = 2; // Hypercube
 net->rows = 0;
 net->cols = dimensions;

 for (int i = 0; i < net->num_nodes; i++) {
 net->nodes[i].node_id = i;
 net->nodes[i].num_neighbors = dimensions;
 net->nodes[i].queue_front = 0;
 net->nodes[i].queue_rear = 0;

 // Each node connects to nodes differing by one bit
 for (int dim = 0; dim < dimensions; dim++) {
 net->nodes[i].neighbors[dim] = i ^ (1 << dim);
 }
 }
}

// Get node coordinates in mesh
void get_mesh_coords(int node_id, int cols, int *row, int *col) {
 *row = node_id / cols;
 *col = node_id % cols;
}

// Dimension-order routing (XY routing) for mesh
int mesh_route(Network *net, int current, int dest) {
 int curr_row, curr_col;
 int dest_row, dest_col;

 get_mesh_coords(current, net->cols, &curr_row, &curr_col);
 get_mesh_coords(dest, net->cols, &dest_row, &dest_col);

 // First try to move in X direction
 if (curr_col < dest_col) {
 return current + 1; // Move east
 } else if (curr_col > dest_col) {
 return current - 1; // Move west
 } else if (curr_row < dest_row) {
 return current + net->cols; // Move south
 } else if (curr_row > dest_row) {
 return current - net->cols; // Move north
 }

 return current; // Already at destination
}

// Hypercube routing using dimension-order
int hypercube_route(Network *net, int current, int dest) {
 int xor_result = current ^ dest;

 // Find the least significant set bit
 for (int i = 0; i < net->cols; i++) {
 if (xor_result & (1 << i)) {
 return current ^ (1 << i); // Toggle bit i
 }
 }

 return current; // Already at destination
}

// Simulate packet transmission
int simulate_packet(Network *net, int source, int dest, int verbose) {
 Packet packet;
 packet.source = source;
 packet.destination = dest;
 packet.current_node = source;
 packet.hops = 0;

 if (verbose) {
 printf("Packet from node %d to node %d\n", source, dest);
 printf("Path: %d ", source);
 }

 // Route until destination reached
 while (packet.current_node != packet.destination) {
 packet.hops++;

 if (net->topology_type == 1) {
 packet.current_node = mesh_route(net, packet.current_node, dest);
 } else {
 packet.current_node = hypercube_route(net, packet.current_node, dest);
 }

 if (verbose) {
 printf("-> %d ", packet.current_node);
 }
 }

 if (verbose) {
 printf("\nTotal hops: %d\n", packet.hops);
 }

 return packet.hops;
}

// Calculate network diameter using BFS
int calculate_diameter_bfs(Network *net, int start_node) {
 int visited[MAX_NODES] = {0};
 int queue[MAX_NODES];
 int front = 0, rear = 0;
 int max_distance = 0;

 queue[rear++] = start_node;
 visited[start_node] = 1;

 int distance[MAX_NODES];
 memset(distance, -1, sizeof(distance));
 distance[start_node] = 0;

 while (front < rear) {
 int current = queue[front++];

 for (int i = 0; i < net->nodes[current].num_neighbors; i++) {
 int neighbor = net->nodes[current].neighbors[i];

 if (!visited[neighbor]) {
 visited[neighbor] = 1;
 distance[neighbor] = distance[current] + 1;
 queue[rear++] = neighbor;

 if (distance[neighbor] > max_distance) {
 max_distance = distance[neighbor];
 }
 }
 }
 }

 return max_distance;
}

// Calculate network diameter
int calculate_network_diameter(Network *net) {
 int diameter = 0;

 for (int i = 0; i < net->num_nodes; i++) {
 int dist = calculate_diameter_bfs(net, i);
 if (dist > diameter) {
 diameter = dist;
 }
 }

 return diameter;
}

// Print network information
void print_network_info(Network *net) {
 printf("Network Information:\n");
 printf(" Number of nodes: %d\n", net->num_nodes);
 printf(" Topology: %s\n", 
 net->topology_type == 1 ? "2D Mesh" : "Hypercube");

 if (net->topology_type == 1) {
 printf(" Dimensions: %d x %d\n", net->rows, net->cols);
 } else {
 printf(" Dimensions: %d\n", net->cols);
 }

 // Calculate average degree
 int total_degree = 0;
 for (int i = 0; i < net->num_nodes; i++) {
 total_degree += net->nodes[i].num_neighbors;
 }
 printf(" Average degree: %.2f\n", (float)total_degree / net->num_nodes);

 int diameter = calculate_network_diameter(net);
 printf(" Diameter: %d\n", diameter);
}

int main() {
 printf("=== Interconnection Network Simulation ===\n\n");

 // Test 4x4 Mesh Network
 Network mesh_net;
 init_mesh_network(&mesh_net, 4, 4);

 printf("--- 4x4 Mesh Network ---\n");
 print_network_info(&mesh_net);
 printf("\nRouting examples:\n");
 simulate_packet(&mesh_net, 0, 15, 1);
 simulate_packet(&mesh_net, 0, 5, 1);

 printf("\n");

 // Test 3-cube (8 nodes) Network
 Network hyper_net;
 init_hypercube_network(&hyper_net, 3);

 printf("--- 3-Cube Hypercube Network ---\n");
 print_network_info(&hyper_net);
 printf("\nRouting examples:\n");
 simulate_packet(&hyper_net, 0, 7, 1);
 simulate_packet(&hyper_net, 0, 3, 1);

 // Performance comparison
 printf("\n\n--- Performance Metrics Comparison ---\n");
 printf("\nFor 16 nodes:\n");

 // Ring
 printf("Ring: Degree=2, Diameter=8, Bisection BW=2\n");
 // Mesh 4x4
 printf("Mesh 4x4: Degree=4, Diameter=6, Bisection BW=4\n");
 // Hypercube 4-cube (16 nodes, but we use 8 for 2^3)
 printf("Hypercube 3: Degree=3, Diameter=3, Bisection BW=4\n");

 return 0;
}
